#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    const int MAX_T = 1000;
    vector<int> buckets_in_use(MAX_T + 2, 0);

    for (int i = 0; i < N; i++) {
        int s, t, b;
        cin >> s >> t >> b;
        buckets_in_use[s] += b;
        buckets_in_use[t + 1] -= b;
    }

    int current = 0;
    int max_buckets = 0;
    for (int time = 1; time <= MAX_T + 1; time++) {
        current += buckets_in_use[time];
        if (current > max_buckets) {
            max_buckets = current;
        }
    }

    cout << max_buckets << "\n";
    return 0;
}
